features.snippet:
reg [2:0] state;
always @(posedge clk or negedge reset)
    if(!reset) state <= 0;
    else case(state)
        0: state <= 1;
        1: state <= 2;
        2: state <= 3;
    endcase

reg [2:0] state;
always @(posedge divcnt or negedge reset)
    if(!reset) state <= 3'b010;
    else state <= state + 1;

reg [2:0] state;
always @(posedge clk or negedge rst_n)
    if(!rst_n) state <= 0;
    else case(state)
        0: state <= 1;
        1: state <= 2;
        2: state <= 3;
        3: state <= 4;
        4: state <= 5;
        5: state <= 0;
    endcase
